    this.windows[this.windows.length] = {instance:newWin, uri:uri, name:name, features:features};
    for(var i=0;i<this.listeners.length;i++) {
      this.listeners[i]('open', newWin, uri, name, features, title);
    }
    return newWin;
  }
},
