  for(var i=0;i<this.windows.length;i++) {
    if(!this.windows[i].instance.closed) {
      try {
        this.windows[i].instance.WCFWindow.clearDirtyState();
      } catch(e) {}
      this.windows[i].instance.close();
    }
  }
  this.windows = new Array;
},
existOpenWindows:function() {
  var winCounter = 0;
  var dirtyCounter = 0;
  for(var i=0;i<this.windows.length;i++) {
    if(!this.windows[i].instance.closed) {
      winCounter++;
      try {
        if(this.windows[i].instance.WCFWindow.getDirty() ) dirtyCounter++;
      } catch(e) {}
    }
  }
  if(winCounter+dirtyCounter > 0) {
    var text = this.closeWarningText.replace('&1',winCounter);
    return text.replace('&2',dirtyCounter);
  }
},
